import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const b=JSON.parse('{"title":"颐和园历史","description":"","frontmatter":{},"headers":[],"relativePath":"history/summer-palace.md","filePath":"history/summer-palace.md","lastUpdated":null}'),o={name:"history/summer-palace.md"};function d(n,t,h,i,s,c){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="颐和园历史" tabindex="-1">颐和园历史 <a class="header-anchor" href="#颐和园历史" aria-label="Permalink to &quot;颐和园历史&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1599577170594-50c2845c7f12?w=1200" alt="颐和园历史"></p><blockquote><p>&quot;颐和园里看沧桑，万园之园梦一场。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>颐和园，原名清漪园，始建于清乾隆十五年（1750年），是中国保存最完整的皇家园林。这座园林见证了中国近代史上最屈辱的一页，也承载着中华民族从衰落走向复兴的历史记忆。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-20:00（旺季），6:30-19:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">30元，联票60元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁4号线北宫门站</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="清漪园时期-1750-1860" tabindex="-1">清漪园时期（1750-1860） <a class="header-anchor" href="#清漪园时期-1750-1860" aria-label="Permalink to &quot;清漪园时期（1750-1860）&quot;">​</a></h3><p>清乾隆十五年（1750年），乾隆皇帝为庆祝母亲六十大寿，下令修建清漪园。工程历时15年，耗银440余万两。</p><h3 id="焚毁与重建-1860-1895" tabindex="-1">焚毁与重建（1860-1895） <a class="header-anchor" href="#焚毁与重建-1860-1895" aria-label="Permalink to &quot;焚毁与重建（1860-1895）&quot;">​</a></h3><h4 id="英法联军焚毁" tabindex="-1">英法联军焚毁 <a class="header-anchor" href="#英法联军焚毁" aria-label="Permalink to &quot;英法联军焚毁&quot;">​</a></h4><p>1860年10月，第二次鸦片战争期间，英法联军焚毁了圆明园、清漪园等皇家园林。</p><h4 id="挪用海军军费重建" tabindex="-1">挪用海军军费重建 <a class="header-anchor" href="#挪用海军军费重建" aria-label="Permalink to &quot;挪用海军军费重建&quot;">​</a></h4><p>1885年，慈禧太后以&quot;颐养天年&quot;为名，下令重建清漪园。工程历时7年，耗银3000余万两，其中大部分来自海军军费。</p><p>这笔经费本应用于购买军舰、建设海军，却被挪用修建园林。甲午战争中北洋水师全军覆没，与这笔经费的挪用不无关系。</p><h4 id="改名颐和园" tabindex="-1">改名颐和园 <a class="header-anchor" href="#改名颐和园" aria-label="Permalink to &quot;改名颐和园&quot;">​</a></h4><p>1888年，重建工程完工，改名&quot;颐和园&quot;。</p><h3 id="慈禧的晚年-1888-1908" tabindex="-1">慈禧的晚年（1888-1908） <a class="header-anchor" href="#慈禧的晚年-1888-1908" aria-label="Permalink to &quot;慈禧的晚年（1888-1908）&quot;">​</a></h3><h4 id="戊戌变法" tabindex="-1">戊戌变法 <a class="header-anchor" href="#戊戌变法" aria-label="Permalink to &quot;戊戌变法&quot;">​</a></h4><p>1898年，光绪皇帝在颐和园仁寿殿召见康有为，开始戊戌变法。但变法仅进行了103天就被慈禧太后发动政变而失败。</p><h4 id="珍妃殉难" tabindex="-1">珍妃殉难 <a class="header-anchor" href="#珍妃殉难" aria-label="Permalink to &quot;珍妃殉难&quot;">​</a></h4><p>1900年八国联军侵华时，慈禧太后在逃离北京前，命人将珍妃推入井中溺死。这口井被称为&quot;珍妃井&quot;，至今仍在颐和园中。</p><h2 id="历史见证" tabindex="-1">历史见证 <a class="header-anchor" href="#历史见证" aria-label="Permalink to &quot;历史见证&quot;">​</a></h2><h3 id="石舫" tabindex="-1">石舫 <a class="header-anchor" href="#石舫" aria-label="Permalink to &quot;石舫&quot;">​</a></h3><p>石舫又名清晏舫，是乾隆时期建造的一座石船。1860年被焚毁，船舱木质结构化为灰烬，只剩下石质船身。</p><p><img src="https://images.unsplash.com/photo-1508804185872-d7badad00f7d?w=800" alt="石舫"></p><h3 id="长廊" tabindex="-1">长廊 <a class="header-anchor" href="#长廊" aria-label="Permalink to &quot;长廊&quot;">​</a></h3><p>长廊全长728米，是中国园林中最长的游廊。廊上绘有14000余幅彩画，这些彩画在1860年被破坏，现存为光绪年间重绘。</p><h2 id="近代人物" tabindex="-1">近代人物 <a class="header-anchor" href="#近代人物" aria-label="Permalink to &quot;近代人物&quot;">​</a></h2><h3 id="乾隆皇帝" tabindex="-1">乾隆皇帝 <a class="header-anchor" href="#乾隆皇帝" aria-label="Permalink to &quot;乾隆皇帝&quot;">​</a></h3><p>清漪园的创建者，对园林艺术有着极高的造诣。</p><h3 id="慈禧太后" tabindex="-1">慈禧太后 <a class="header-anchor" href="#慈禧太后" aria-label="Permalink to &quot;慈禧太后&quot;">​</a></h3><p>颐和园的实际主人，晚年的主要居所。她在这里&quot;颐养天年&quot;，也在这里处理政务、发动政变。</p><h3 id="光绪皇帝" tabindex="-1">光绪皇帝 <a class="header-anchor" href="#光绪皇帝" aria-label="Permalink to &quot;光绪皇帝&quot;">​</a></h3><p>在颐和园被软禁，戊戌变法失败后被囚禁于瀛台，度过了人生最后的十年。</p><h3 id="珍妃" tabindex="-1">珍妃 <a class="header-anchor" href="#珍妃" aria-label="Permalink to &quot;珍妃&quot;">​</a></h3><p>光绪皇帝的宠妃，因支持变法而得罪慈禧太后，1900年被推入井中溺死。</p><h2 id="历史意义" tabindex="-1">历史意义 <a class="header-anchor" href="#历史意义" aria-label="Permalink to &quot;历史意义&quot;">​</a></h2><h3 id="屈辱的见证" tabindex="-1">屈辱的见证 <a class="header-anchor" href="#屈辱的见证" aria-label="Permalink to &quot;屈辱的见证&quot;">​</a></h3><p>颐和园两次被外国侵略者焚毁、洗劫，是近代中国屈辱历史的见证。</p><h3 id="腐败的写照" tabindex="-1">腐败的写照 <a class="header-anchor" href="#腐败的写照" aria-label="Permalink to &quot;腐败的写照&quot;">​</a></h3><p>慈禧挪用海军军费修建园林，是晚清统治阶级腐败的写照。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="历史主题路线" tabindex="-1">历史主题路线 <a class="header-anchor" href="#历史主题路线" aria-label="Permalink to &quot;历史主题路线&quot;">​</a></h3><p><strong>半日游（历史线）</strong>： 东宫门 → 仁寿殿（慈禧垂帘听政处）→ 玉澜堂（光绪寝宫）→ 乐寿堂（慈禧寝宫）→ 长廊 → 排云殿 → 佛香阁 → 石舫 → 十七孔桥 → 东宫门</p><h3 id="必看历史遗迹" tabindex="-1">必看历史遗迹 <a class="header-anchor" href="#必看历史遗迹" aria-label="Permalink to &quot;必看历史遗迹&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">遗迹</th><th style="text-align:left;">历史意义</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>仁寿殿</strong></td><td style="text-align:left;">慈禧垂帘听政处</td></tr><tr><td style="text-align:left;"><strong>玉澜堂</strong></td><td style="text-align:left;">光绪寝宫，戊戌变法失败后被囚禁处</td></tr><tr><td style="text-align:left;"><strong>乐寿堂</strong></td><td style="text-align:left;">慈禧寝宫</td></tr><tr><td style="text-align:left;"><strong>石舫</strong></td><td style="text-align:left;">清漪园被焚毁的见证</td></tr><tr><td style="text-align:left;"><strong>珍妃井</strong></td><td style="text-align:left;">珍妃殉难处</td></tr></tbody></table><h2 id="交通指南" tabindex="-1">交通指南 <a class="header-anchor" href="#交通指南" aria-label="Permalink to &quot;交通指南&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">入口</th><th style="text-align:left;">交通方式</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>东宫门</strong></td><td style="text-align:left;">地铁4号线西苑站C2口</td></tr><tr><td style="text-align:left;"><strong>北宫门</strong></td><td style="text-align:left;">地铁4号线北宫门站D口</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th></tr></thead><tbody><tr><td style="text-align:left;">圆明园</td><td style="text-align:center;">1公里</td></tr><tr><td style="text-align:left;">北京大学</td><td style="text-align:center;">2公里</td></tr><tr><td style="text-align:left;">清华大学</td><td style="text-align:center;">2公里</td></tr></tbody></table><hr><p><strong>💡 Tips</strong>：颐和园是一座&quot;活着&quot;的历史教科书。每一块石头、每一座建筑都承载着历史的记忆。</p>',54)])])}const x=a(o,[["render",d]]);export{b as __pageData,x as default};
